  {
    "id": "rollback_safety",
    "description": "Must include an explicit, tested rollback procedure that does not rely solely on deleting the newly imported Postgres table. If cutover occurs, rollback must account for writes that happened to Postgres during the failed migration window (e.g., via replaying a captured binary log or dumping records back to MySQL).",
    "weight": 2.0,
    "required": true
  },
  {
    "id": "idempotency",
    "description": "The migration execution steps must be idempotent or explicitly state how to safely resume an interrupted run without creating duplicate users or overwriting newer records with older ones.",
    "weight": 1.5,
    "required": true
  },
  {
    "id": "schema_translation",
    "description": "Must address data type conversions, specifically MySQL TINYINT(1) to Postgres BOOLEAN, MySQL DATETIME to Postgres TIMESTAMP (or TIMESTAMPTZ), and UNSIGNED INT constraints, providing explicit DDL or migration tool mappings rather than relying on automated defaults.",
    "weight": 1.5,
    "required": false
  },
  {
    "id": "secret_handling",
    "description": "Must explicitly prohibit dumping plaintext passwords and dictate that bcrypt/argon2 hashes are migrated as raw strings without modification, ensuring the Postgres column type accommodates the full length of the hash.",
    "weight": 1.0,
    "required": true
  },
  {
    "id": "data_validation",
    "description": "Must include a post-migration validation step that checks row counts, validates primary key max/min bounds, and spot-checks a randomized sample of 100 users for field-level data integrity.",
    "weight": 1.5,
    "required": true
  },
  {
    "id": "cutover_strategy",
    "description": "Must define the downtime expectations and a clear cutover sequence (e.g., read-only mode, dump, import, verify, switch app config) including who executes the switch and how traffic is routed to the new database.",
    "weight": 1.0,
    "required": false
  },
  {
    "id": "id_sequence_sync",
    "description": "Must explicitly include a step to reset the Postgres SERIAL/IDENTITY sequence for the users table to MAX(id) + 1 to prevent primary key collisions on subsequent new user inserts.",
    "weight": 1.0,
    "required": true
  }
]

